import { useState } from "react"; 

import { Search } from "lucide-react";
import VerbCard from "../verb/VerbCard";
import Modal from "../verb/Modal";
import { words } from "../../data/word";

const WordList = () => {
  const [selected, setSelected] = useState(null);
  const [search, setSearch] = useState("");

  const filtered = words.filter(
    (w) =>
      w.base.toLowerCase().includes(search.toLowerCase()) ||
      w.base.toLowerCase().includes(search.toLowerCase()),
  );

  return (
    <div className="space-y-4 w-full max-w-4xl mx-auto px-2 sm:px-4 md:px-6 bg-[rgb(26_24_41/var(--tw-bg-opacity,1))] rounded-2xl p-6 sm:p-8 transition-colors border border-gray-700">
      <h1 className="text-xl sm:text-2xl md:text-3xl font-bold mb-4 text-gray-800 dark:text-gray-100 text-center">
        Words Learning
      </h1>
      <p className="text-white">
        <span className="text-green-500 font-bold">{words.length}</span> words
        available.
      </p>
      {/* Search */}
      <div className="relative mb-5">
        <Search
          size={14}
          className="absolute text-white left-3 top-1/2 -translate-y-1/2 text-muted"
        />
        <input
          type="text"
          placeholder="Search vocabulary..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full bg- border border-white/[0.07] focus:border-accent/40 rounded-xl pl-9 pr-4 py-2.5 text-sm text-white placeholder-muted outline-none transition-colors font-sans"
        />
      </div>
      {filtered.map((v, i) => (
        <VerbCard key={i} verb={v} onSelect={setSelected} />
      ))}
      {filtered.length === 0 && (
        <p className="text-center text-muted text-white text-sm py-6">
          No words found for &quot;{search}&quot;
        </p>
      )}

      <Modal data={selected} onClose={() => setSelected(null)} />
    </div>
  );
};

export default WordList;
